constexpr int SZO_LEN = sizeof(szo);
constexpr int MONDAT_LEN = sizeof(mondat);
constexpr int POSITIONS = MONDAT_LEN - SZO_LEN + 1;
constexpr int BLOCK_SIZE = MONDAT_LEN / 1024 + 1;

dim3 block(BLOCK_SIZE, SZO_LEN - 1);
dim3 grid((POSITIONS + block.x - 1) / block.x);

int result = -1;

__device__ char dev_szo[SZO_LEN];

__device__ char dev_mondat[MONDAT_LEN];

__device__ int dev_result;

__device__ char dev_temp[MONDAT_LEN];

__global__ void szokeres() {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = threadIdx.y;

    if (x >= POSITIONS || y >= SZO_LEN - 1) return;

    __shared__ int match[BLOCK_SIZE];

    if (y == 0) {
        match[threadIdx.x] = 1;
    }

    __syncthreads();

    if (dev_mondat[x + y] != dev_szo[y]) {
        match[threadIdx.x] = 0;
    }

    __syncthreads();

    if (y == 0 && match[threadIdx.x]) {
        dev_result = x;
    }
}

int main(){
    cudaMemcpyToSymbol(dev_szo, szo, sizeof(szo));
    cudaMemcpyToSymbol(dev_mondat, mondat, sizeof(mondat));
    cudaMemcpyToSymbol(dev_result, &result, sizeof(int));
    szokeres<<<grid, block>>>();
    cudaDeviceSynchronize();
    cudaMemcpyFromSymbol(&result, dev_result, sizeof(int));    

    printf("%d\n", result);
    printf("%d\n", BLOCK_SIZE);

    return 0;

}